72: // internal API objects. Attempting to set or retrieve a field on an object that does
73: // not support that field will be a no-op and return a default value.
74: // TODO: move this, and TypeMeta and ListMeta, to a different package
75: type Common interface {
76: 	GetResourceVersion() string
77: 	SetResourceVersion(version string)
78: 	GetSelfLink() string
79: 	SetSelfLink(selfLink string)
80: }
81: 
82: // ListInterface lets you work with list metadata from any of the versioned or
83: // internal API objects. Attempting to set or retrieve a field on an object that does
84: // not support that field will be a no-op and return a default value.
85: // TODO: move this, and TypeMeta and ListMeta, to a different package
86: type ListInterface interface {
87: 	GetResourceVersion() string
88: 	SetResourceVersion(version string)
89: 	GetSelfLink() string
90: 	SetSelfLink(selfLink string)
91: 	GetContinue() string
92: 	SetContinue(c string)
93: 	GetRemainingItemCount() *int64
94: 	SetRemainingItemCount(c *int64)
95: }
